using UnityEngine;

/// <summary>
/// Implementado por objectos destrutíveis (ex: pedras/blocos — Etapa 6+) que
/// reagem a projécteis com <see cref="ProjectileData.canDestroyObjects"/>.
/// </summary>
public interface IProjectileDestructible
{
    void DestroyByProjectile(ProjectileController projectile);
}

/// <summary>
/// Implementado por switches/botões/alvos (ex: Etapa 6.1+) activáveis por
/// projécteis com <see cref="ProjectileData.canActivateSwitches"/>.
/// </summary>
public interface IProjectileActivatable
{
    void ActivateByProjectile(ProjectileController projectile);
}

/// <summary>
/// Implementado por objectos (escudos/espelhos) que reflectem projécteis com
/// <see cref="ProjectileData.canBeReflected"/>.
/// </summary>
public interface IProjectileReflector
{
    Vector2 GetReflectedVelocity(Vector2 incomingVelocity, Vector2 hitPoint);
}

/// <summary>
/// Projéctil runtime (Enemy Creator — Etapa 2.2). Generaliza/substitui o antigo
/// EnemyProjectile (Etapa 2.1, placeholder): toda a configuração vem de
/// <see cref="ProjectileData"/>. Obtido de <see cref="ProjectilePool"/> (Tarefa
/// #22 — pooling) por <see cref="EnemyAttackController.SpawnProjectile"/>,
/// chamado pelos ataques de projéctil da Etapa 2.1
/// (Attack_ProjectileStraight/Arc/Homing, Attack_SpawnEnemyOrProjectile).
/// </summary>
[RequireComponent(typeof(Rigidbody2D))]
public class ProjectileController : MonoBehaviour
{
    [Tooltip("Configuração deste projéctil. Definida automaticamente por EnemyAttackController.SpawnProjectile (via ProjectilePool.Get + Activate).")]
    public ProjectileData data;

    /// <summary>Velocidade inicial (direcção × magnitude). Para "Arco", já inclui a componente vertical calculada pelo EnemyAttack.</summary>
    [HideInInspector] public Vector2 initialVelocity;

    /// <summary>Alvo a perseguir, se <see cref="ProjectileData.tracksPlayer"/>.</summary>
    [HideInInspector] public Transform target;

    /// <summary>Inimigo que disparou — usado para não se atingir a si próprio e para "fere outros inimigos?".</summary>
    [HideInInspector] public EnemyController owner;

    /// <summary>
    /// Chave de pooling (Tarefa #22) — atribuída por <see cref="ProjectilePool"/>
    /// ao criar este projéctil pela primeira vez (o "prefab" de origem, ou o
    /// próprio <see cref="ProjectileData"/> quando não há prefab customizado).
    /// Usada por <see cref="ProjectilePool.Release"/> para devolver este
    /// objecto à fila correcta.
    /// </summary>
    internal Object PoolKey;

    private Rigidbody2D _rb;
    private float _life;
    private bool _resolved;

    private void Awake()
    {
        _rb = GetComponent<Rigidbody2D>();
    }

    /// <summary>
    /// (Re)inicializa este projéctil — chamado por
    /// <see cref="EnemyAttackController.SpawnSingleProjectile"/> depois de
    /// obtê-lo de <see cref="ProjectilePool"/> e posicioná-lo. Substitui o
    /// antigo Start() para suportar reutilização (pooling): repõe o tempo de
    /// vida, o estado "resolvido" e a velocidade/gravidade.
    /// </summary>
    public void Activate(ProjectileData data, Vector2 initialVelocity, Transform target, EnemyController owner)
    {
        this.data = data;
        this.initialVelocity = initialVelocity;
        this.target = target;
        this.owner = owner;

        _life = 0f;
        _resolved = false;

        if (data == null) { ReleaseSelf(); return; }

        if (data.isLaser)
        {
            FireLaserAndDestroy();
            return;
        }

        _rb.angularVelocity = 0f;
        _rb.gravityScale = data.gravityScale;
        _rb.velocity = initialVelocity;

        PlaySound(data.fireSound);
    }

    private void Update()
    {
        if (data == null || data.isLaser) return;

        _life += Time.deltaTime;
        if (_life >= data.lifetime)
        {
            ReleaseSelf();
            return;
        }

        if (data.tracksPlayer && target != null)
            ApplyTracking();
    }

    /// <summary>Curva suavemente a velocidade actual em direcção a "target", proporcional a "trackingIntensity".</summary>
    private void ApplyTracking()
    {
        Vector2 toTarget = (Vector2)target.position - (Vector2)transform.position;
        if (toTarget.sqrMagnitude < 0.0001f) return;

        Vector2 current = _rb.velocity.sqrMagnitude > 0.0001f ? _rb.velocity.normalized : toTarget.normalized;
        Vector2 desired = toTarget.normalized;
        float speed = _rb.velocity.magnitude;

        float maxTurnRad = Mathf.Lerp(0f, 360f, data.trackingIntensity) * Mathf.Deg2Rad * Time.deltaTime;
        Vector2 newDir = Vector3.RotateTowards(current, desired, maxTurnRad, 0f);

        _rb.velocity = newDir.normalized * speed;
    }

    private void OnTriggerEnter2D(Collider2D other) => HandleHit(other);
    private void OnCollisionEnter2D(Collision2D collision) => HandleHit(collision.collider);

    private void HandleHit(Collider2D other)
    {
        if (_resolved || data == null) return;

        // Nunca acerta em quem o disparou (evita auto-dano no instante do spawn).
        if (owner != null && other.gameObject == owner.gameObject) return;

        // Reflexão (escudos/espelhos — pode ser reflectido?)
        if (data.canBeReflected)
        {
            var reflector = other.GetComponent<IProjectileReflector>();
            if (reflector != null)
            {
                _rb.velocity = reflector.GetReflectedVelocity(_rb.velocity, transform.position);
                owner = null; // já não pertence a ninguém — pode agora ferir quem o disparou
                return;
            }
        }

        // Player
        if (other.CompareTag("Player"))
        {
            ApplyHitToPlayer(other.transform);
            Resolve(playerDirectlyHit: true);
            return;
        }

        // Outros inimigos (fere outros inimigos? + o receptor aceita dano de projécteis de inimigos?)
        var enemyHealth = other.GetComponent<EnemyHealth>();
        if (enemyHealth != null)
        {
            if (CanHurtEnemy(enemyHealth))
            {
                enemyHealth.TakeDamage(data.damage, transform.position, data.knockbackForce);
                Resolve();
            }
            else if (EnemyBlocksProjectiles(enemyHealth))
            {
                // Inimigo-escudo (Etapa 6.2 — canBlockLaser): o projéctil é
                // bloqueado/consumido mesmo sem causar dano.
                Resolve();
            }

            return;
        }

        // Objectos destrutíveis (destrói objectos/pedras?)
        var destructible = other.GetComponent<IProjectileDestructible>();
        if (destructible != null)
        {
            if (data.canDestroyObjects) destructible.DestroyByProjectile(this);
            Resolve();
            return;
        }

        // Switches/botões (activa switches/botões?)
        var activatable = other.GetComponent<IProjectileActivatable>();
        if (activatable != null)
        {
            if (data.canActivateSwitches) activatable.ActivateByProjectile(this);
            Resolve();
            return;
        }

        // Cenário sólido (paredes/chão) — qualquer outro collider não-trigger.
        if (!other.isTrigger)
            Resolve();
    }

    private void ApplyHitToPlayer(Transform player)
    {
        // P2: passa pelo ponto de entrada único (i-frames + Defesa + TakeHit).
        PlayerCombat.TryDamagePlayer(player, new DamageInfo(data.damage, DamageType.Projectile, transform.position, data.knockbackForce));
    }

    /// <summary>
    /// True se este projéctil pode ferir o inimigo "eh": o lado do atirador tem
    /// de permitir (ProjectileData.canHurtOtherEnemies OU
    /// EnemyWeaknessConfig.canHurtOtherEnemies de quem disparou) e o lado do
    /// receptor tem de aceitar (canTakeDamageFromOtherEnemyProjectiles).
    /// </summary>
    private bool CanHurtEnemy(EnemyHealth eh)
    {
        if (eh == null) return false;
        if (owner != null && eh.gameObject == owner.gameObject) return false;

        bool shooterAllows = data.canHurtOtherEnemies ||
            (owner != null && owner.Data != null && owner.Data.weaknesses.canHurtOtherEnemies);
        if (!shooterAllows) return false;

        var receiver = eh.GetComponent<EnemyController>();
        return receiver == null || receiver.Data == null ||
               receiver.Data.weaknesses.canTakeDamageFromOtherEnemyProjectiles;
    }

    /// <summary>True se o inimigo "eh" bloqueia projécteis/lasers (EnemyWeaknessConfig.canBlockLaser — Etapa 6.2, inimigo-escudo).</summary>
    private static bool EnemyBlocksProjectiles(EnemyHealth eh)
    {
        var ctrl = eh != null ? eh.GetComponent<EnemyController>() : null;
        return ctrl != null && ctrl.Data != null && ctrl.Data.weaknesses.canBlockLaser;
    }

    /// <summary>
    /// Dano em área ao colidir (explode ao colidir? + raio/dano). Atinge o
    /// player (excepto se já tiver levado o dano directo deste impacto) e os
    /// EnemyHealth na área permitidos por <see cref="CanHurtEnemy"/>.
    /// </summary>
    private void Explode(bool skipPlayer)
    {
        var hits = Physics2D.OverlapCircleAll(transform.position, data.explosionRadius);

        foreach (var hit in hits)
        {
            if (hit.CompareTag("Player"))
            {
                if (!skipPlayer)
                    PlayerCombat.TryDamagePlayer(hit.transform, new DamageInfo(data.explosionDamage, DamageType.Explosion, transform.position, data.knockbackForce));
                continue;
            }

            var eh = hit.GetComponent<EnemyHealth>();
            if (eh != null && CanHurtEnemy(eh))
                eh.TakeDamage(data.explosionDamage, transform.position, data.knockbackForce);
        }
    }

    /// <summary>
    /// Fim de vida do projéctil ao tocar algo: explode (se "explodesOnImpact" —
    /// agora em QUALQUER impacto: player, parede, chão, objecto — para bombas
    /// que caem de cima), toca o som de impacto e devolve-se ao pool (ou
    /// destrói-se, se não tiver sido criado por um pool).
    /// </summary>
    private void Resolve(bool playerDirectlyHit = false)
    {
        if (_resolved) return;
        _resolved = true;

        if (data.explodesOnImpact)
            Explode(skipPlayer: playerDirectlyHit); // evita dano a dobrar no hit directo

        PlaySound(data.impactSound);
        ReleaseSelf();
    }

    /// <summary>
    /// Devolve este projéctil a <see cref="ProjectilePool"/> (Tarefa #22) para
    /// reutilização, ou destrói-o se não tiver sido criado por um pool (ex:
    /// colocado manualmente numa cena de testes).
    /// </summary>
    private void ReleaseSelf()
    {
        if (ProjectilePool.Instance != null && PoolKey != null)
            ProjectilePool.Instance.Release(this);
        else
            Destroy(gameObject);
    }

    /// <summary>Variante "laser": raio instantâneo (Raycast) ao longo de "initialVelocity", sem deslocamento físico.</summary>
    private void FireLaserAndDestroy()
    {
        Vector2 origin = transform.position;
        Vector2 dir = initialVelocity.sqrMagnitude > 0.0001f ? initialVelocity.normalized : Vector2.right;

        var hits = Physics2D.RaycastAll(origin, dir, data.laserRange);
        System.Array.Sort(hits, (a, b) => a.distance.CompareTo(b.distance));

        foreach (var hit in hits)
        {
            if (owner != null && hit.collider.gameObject == owner.gameObject) continue;

            if (hit.collider.CompareTag("Player"))
            {
                ApplyHitToPlayer(hit.collider.transform);
                break;
            }

            var enemyHealth = hit.collider.GetComponent<EnemyHealth>();
            if (enemyHealth != null)
            {
                if (CanHurtEnemy(enemyHealth))
                    enemyHealth.TakeDamage(data.damage, transform.position, data.knockbackForce);

                // Inimigo-escudo (Etapa 6.2): bloqueia a continuação do raio.
                if (EnemyBlocksProjectiles(enemyHealth)) break;

                continue;
            }

            if (data.canDestroyObjects)
            {
                var destructible = hit.collider.GetComponent<IProjectileDestructible>();
                if (destructible != null) destructible.DestroyByProjectile(this);
            }

            if (data.canActivateSwitches)
            {
                var activatable = hit.collider.GetComponent<IProjectileActivatable>();
                if (activatable != null) activatable.ActivateByProjectile(this);
            }

            if (!hit.collider.isTrigger) break; // bloqueado por cenário sólido
        }

        PlaySound(data.fireSound);
        _resolved = true;
        ReleaseSelf();
    }

    private void PlaySound(AudioClip clip)
    {
        if (clip != null) AudioSource.PlayClipAtPoint(clip, transform.position);
    }

    /// <summary>
    /// Cria um GameObject simples (Sprite + Rigidbody2D + CircleCollider2D
    /// trigger + ProjectileController) para "data", usado por
    /// <see cref="ProjectilePool"/> quando "data" não define um "prefab"
    /// customizado. Movido de EnemyAttackController (Tarefa #22) para junto do
    /// resto da lógica de projécteis.
    /// </summary>
    public static GameObject CreateDefaultProjectileObject(ProjectileData data, Vector3 pos)
    {
        var go = new GameObject(string.IsNullOrEmpty(data.displayName) ? "Projectile" : data.displayName);
        go.transform.position = pos;

        if (data.sprite != null)
            go.AddComponent<SpriteRenderer>().sprite = data.sprite;

        var rb = go.AddComponent<Rigidbody2D>();
        rb.gravityScale = 0f;

        var col = go.AddComponent<CircleCollider2D>();
        col.isTrigger = true;
        col.radius = 0.2f;

        go.AddComponent<ProjectileController>();

        return go;
    }
}
